theme.custom_css_code:
.mrvegas-wrap{
    width:100%;
    background:transparent;
    font-family:Arial,sans-serif;
    color:#ffffff;
  }
  .mrvegas-grid{
    display:grid;
    grid-template-columns:1fr;
    gap:24px;
  }
  .mrvegas-card{
    background:#000000;
    border:1px solid rgba(255,255,255,0.14);
    border-radius:18px;
    padding:20px;
    box-sizing:border-box;
    overflow:hidden;
  }
  .mrvegas-table-wrap{
    width:100%;
    overflow-x:auto;
  }
  .mrvegas-table{
    width:100%;
    min-width:640px;
    border-collapse:collapse;
    color:#ffffff;
  }
  .mrvegas-table td{
    padding:14px 16px;
    border-bottom:1px solid rgba(255,255,255,0.1);
    vertical-align:top;
    font-size:15px;
    line-height:1.45;
  }
  .mrvegas-table tr:last-child td{
    border-bottom:none;
  }
  .mrvegas-table td:first-child{
    width:34%;
    color:rgba(255,255,255,0.72);
  }
  .chart-stack{
    display:grid;
    gap:16px;
  }
  .chart-row{
    display:grid;
    grid-template-columns:140px 1fr 52px;
    gap:12px;
    align-items:center;
  }
  .chart-label{
    font-size:14px;
    line-height:1.3;
    color:#ffffff;
    word-break:break-word;
  }
  .chart-track{
    position:relative;
    height:16px;
    background:rgba(255,255,255,0.08);
    border-radius:999px;
    overflow:hidden;
  }
  .chart-fill{
    position:absolute;
    left:0;
    top:0;
    bottom:0;
    border-radius:999px;
    background:linear-gradient(90deg,#6d5dfc 0%,#00d4ff 100%);
  }
  .chart-fill.alt{
    background:linear-gradient(90deg,#19c37d 0%,#7dffb3 100%);
  }
  .chart-value{
    text-align:right;
    font-size:14px;
    color:rgba(255,255,255,0.82);
  }
  .compare-grid{
    display:grid;
    gap:18px;
  }
  .compare-row{
    display:grid;
    grid-template-columns:130px 1fr;
    gap:14px;
    align-items:center;
  }
  .compare-bars{
    display:grid;
    gap:8px;
  }
  .mini-line{
    display:grid;
    grid-template-columns:78px 1fr 40px;
    gap:10px;
    align-items:center;
  }
  .mini-tag{
    font-size:12px;
    color:rgba(255,255,255,0.72);
  }
  .mini-track{
    position:relative;
    height:12px;
    background:rgba(255,255,255,0.08);
    border-radius:999px;
    overflow:hidden;
  }
  .mini-fill{
    position:absolute;
    inset:0 auto 0 0;
    border-radius:999px;
    background:linear-gradient(90deg,#f5c542 0%,#ff8a00 100%);
  }
  .mini-fill.market{
    background:linear-gradient(90deg,#6a6a6a 0%,#9a9a9a 100%);
  }
  .mini-value{
    text-align:right;
    font-size:12px;
    color:rgba(255,255,255,0.75);
  }
  @media (max-width:720px){
    .mrvegas-card{
      padding:16px;
      border-radius:14px;
    }
    .chart-row{
      grid-template-columns:1fr;
      gap:8px;
    }
    .chart-value{
      text-align:left;
    }
    .compare-row{
      grid-template-columns:1fr;
      gap:10px;
    }
    .mini-line{
      grid-template-columns:68px 1fr 34px;
      gap:8px;
    }
  }
